hooks.command:
branch=$(git branch --show-current 2>/dev/null); if [ "$branch" = "main" ]; then input=$(cat 2>/dev/null); file_path=$(printf '%s' "$input" | python3 -c "import sys,json
try:
    d=json.load(sys.stdin)
    print(d.get('file_path') or d.get('tool_input',{}).get('file_path',''))
except:
    print('')" 2>/dev/null); if echo "$file_path" | grep -q '/docs/plans/'; then exit 0; fi; echo 'BLOCCATO: sei sul branch main. Modifiche permesse solo in docs/plans/. Apri un feature branch.'; exit 2; fi
